import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }
function rpn(e:string,b:string,d:number,s:string,o:string[],c:number,r:string) {
  return {tier:"rpn",exam:e,stem:s,options:o,correct:c,rationale:r,diff:d,bs:b};
}

const QS = [
  rpn("REX-PN","Fundamentals",2,"A nurse is assessing a client and notes a respiratory rate of 28 breaths per minute. This finding is documented as:",["Bradypnea","Tachypnea","Eupnea","Apnea"],1,"Tachypnea is defined as a respiratory rate greater than 20 breaths per minute in adults. Normal adult respiratory rate (eupnea) is 12-20 breaths/min. Bradypnea is less than 12. Apnea is absence of breathing. Tachypnea may indicate pain, anxiety, fever, or respiratory compromise."),
  rpn("REX-PN","Fundamentals",2,"When taking a rectal temperature, the nurse should insert the thermometer to a depth of:",["1 inch in an adult","0.5 inches in an adult","3 inches in an adult","4 inches in an adult"],0,"Rectal thermometer insertion depth: 1 inch (2.5 cm) for adults, 0.5 inch (1.25 cm) for infants. Position the client in Sims position (left lateral). Lubricate the thermometer tip. Hold in place during measurement. Rectal temperature reads approximately 1 degree F higher than oral."),
  rpn("REX-PN","Fundamentals",2,"A nurse is preparing to administer an intramuscular injection to an adult. The preferred site for a large-volume injection is the:",["Deltoid muscle","Ventrogluteal muscle","Vastus lateralis in adults","Dorsogluteal muscle"],1,"The ventrogluteal site is the preferred IM injection site for adults: large muscle mass, well-defined landmarks (anterior superior iliac spine and iliac crest), no major nerves or blood vessels, and accommodates large volumes (up to 3-4 mL). The dorsogluteal site is no longer recommended due to sciatic nerve proximity."),
  rpn("REX-PN","Fundamentals",2,"A client asks the nurse to explain what the pulse oximeter reading of 98% means. The nurse should respond:",["Your heart rate is 98 beats per minute","98% of your hemoglobin is carrying oxygen, which is a normal reading","Your blood pressure is 98 systolic","Your temperature is 98 degrees"],1,"Pulse oximetry measures the percentage of hemoglobin saturated with oxygen (SpO2). Normal is 95-100%. Values below 90% indicate hypoxemia requiring intervention. Factors affecting accuracy include nail polish, poor circulation, hypothermia, anemia, and carbon monoxide poisoning."),
  rpn("REX-PN","Fundamentals",2,"When performing oral suctioning, the nurse should apply suction for no longer than:",["30 seconds","10-15 seconds per pass","1 minute","5 seconds"],1,"Oral suctioning: apply suction intermittently during catheter withdrawal only, limiting each pass to 10-15 seconds to prevent hypoxia, vagal stimulation (bradycardia), and mucosal trauma. Pre-oxygenate if needed. Allow rest between passes. Use a Yankauer suction tip for oral suctioning."),
  rpn("REX-PN","Fundamentals",2,"A client is placed on droplet precautions. The nurse should wear which personal protective equipment when entering the room?",["N95 respirator and gown","Surgical mask within 3-6 feet of the client","Gown and gloves only","Full face shield and sterile gown"],1,"Droplet precautions: surgical mask when within 3-6 feet of the client (or upon room entry per facility policy). Used for influenza, pertussis, meningococcal disease, and streptococcal pharyngitis. Droplets travel short distances and do not remain airborne. Patient may wear a mask during transport."),
  rpn("REX-PN","Fundamentals",2,"The nurse is preparing to perform a sterile dressing change. Which action would contaminate the sterile field?",["Using sterile forceps to arrange supplies on the sterile field","Reaching across the sterile field with an unsterile arm","Opening sterile packages away from the body","Keeping the sterile field within the nurse's line of vision"],1,"Reaching across a sterile field with an unsterile arm or object contaminates the field. Sterile principles: keep the field in view at all times, only sterile items touch sterile areas, consider the 1-inch border non-sterile, moisture compromises sterility, and never turn your back on the field."),
  rpn("REX-PN","Fundamentals",2,"A client has a nasogastric tube for intermittent feedings. Before each feeding, the nurse should verify tube placement by:",["Injecting water and listening for a swooshing sound","Aspirating gastric contents and checking pH (should be acidic, typically below 5.5)","Asking the client if they feel the tube","Measuring the external tube length only"],1,"Gastric aspirate pH below 5.5 confirms gastric placement. X-ray is the gold standard. Auscultation alone is unreliable (air can be heard even with pulmonary placement). Also check external tube marking (migration detection). Verify placement before each intermittent feeding and every 4 hours during continuous feeds."),
  rpn("REX-PN","Pharmacology",2,"A client is prescribed metoprolol. Before administering this medication, the nurse should assess:",["Blood glucose level","Heart rate and blood pressure","Respiratory rate and lung sounds","Urinary output"],1,"Metoprolol is a beta-blocker that decreases heart rate and blood pressure. Hold and notify the provider if HR < 60 bpm or SBP < 100 mmHg. Common side effects include bradycardia, hypotension, fatigue, and dizziness. Do not stop abruptly (rebound tachycardia/hypertension)."),
  rpn("REX-PN","Pharmacology",2,"A nurse is administering insulin lispro (Humalog). The nurse should give this medication:",["At bedtime","Within 15 minutes before or immediately after a meal","Two hours before meals","Without regard to meals"],1,"Insulin lispro is rapid-acting (onset 15 minutes, peak 1-2 hours, duration 3-5 hours). Administer within 15 minutes before meals to cover postprandial glucose spikes. Must be given with food to prevent hypoglycemia. Regular insulin is given 30 minutes before meals."),
  rpn("REX-PN","Pharmacology",2,"A client receiving morphine should be monitored for which adverse effect?",["Hypertension","Respiratory depression","Tachycardia","Diarrhea"],1,"Morphine (opioid analgesic) depresses the respiratory center in the brainstem. Monitor respiratory rate (hold if < 12 breaths/min), level of sedation, and oxygen saturation. Naloxone (Narcan) is the reversal agent. Other side effects include constipation, nausea, urinary retention, and hypotension."),
  rpn("REX-PN","Pharmacology",3,"A nurse is teaching a client about digoxin. Which statement by the client indicates a need for further teaching?",["I will check my pulse before taking this medication","I should report any visual changes like yellow-green halos","I can take this medication with antacids for stomach upset","I should eat foods high in potassium while on this medication"],2,"Antacids decrease digoxin absorption and should not be taken simultaneously (separate by 2 hours). Correct statements: check pulse before taking (hold if < 60), report visual changes (toxicity sign), eat potassium-rich foods (hypokalemia increases digoxin toxicity risk). Therapeutic range: 0.5-2.0 ng/mL."),
  rpn("REX-PN","Pharmacology",2,"A client prescribed ferrous sulfate should be taught to take it with:",["Milk to reduce stomach upset","Orange juice to enhance absorption","Antacids to reduce GI side effects","Coffee for better taste"],1,"Vitamin C (ascorbic acid) in orange juice enhances iron absorption by converting ferric iron to ferrous iron. Avoid taking with dairy (calcium), antacids, coffee, or tea (tannins) as these reduce absorption. Take on an empty stomach if tolerated. Expect dark/black stools."),
  rpn("REX-PN","Pharmacology",3,"A client receiving vancomycin intravenously should be monitored for which infusion-related reaction?",["Hyperkalemia","Red man syndrome (flushing, pruritus, erythema of face and upper body)","Hypertension crisis","Severe constipation"],1,"Red man syndrome is a histamine-mediated reaction from rapid vancomycin infusion (NOT a true allergy). Symptoms: flushing, erythema, pruritus of face/neck/upper body. Prevention: infuse over at least 60 minutes (1 hour per 1 gram). Also monitor trough levels (15-20 mcg/mL for serious infections) and renal function."),
  rpn("REX-PN","Pharmacology",2,"A nurse should teach a client taking ciprofloxacin to avoid:",["All fruits","Dairy products and antacids within 2 hours of taking the medication","Red meat","Leafy green vegetables"],1,"Ciprofloxacin (fluoroquinolone) absorption is reduced by calcium, magnesium, aluminum, and iron-containing products. Avoid dairy, antacids, and supplements within 2 hours before or 6 hours after. Stay hydrated (crystalluria prevention). Avoid excessive sun exposure (photosensitivity). Report tendon pain immediately."),
  rpn("REX-PN","Cardiovascular",2,"A client with heart failure is prescribed a low-sodium diet. The nurse should teach the client to avoid:",["Fresh fruits and vegetables","Canned soups, processed meats, and pickled foods","Whole grains and brown rice","Lean chicken and fish prepared at home"],1,"Processed foods contain high sodium: canned soups (800-1200 mg per serving), deli meats, hot dogs, pickled foods, soy sauce, frozen dinners. Fresh fruits, vegetables, whole grains, and home-prepared lean meats are naturally low in sodium. Target: < 2,000 mg sodium per day in heart failure."),
  rpn("REX-PN","Cardiovascular",3,"A client with atrial fibrillation is receiving warfarin therapy. The nurse should teach the client to:",["Increase vitamin K intake for better clotting","Maintain a consistent intake of vitamin K-containing foods","Eliminate all green vegetables from the diet","Take aspirin with warfarin for better anticoagulation"],1,"Consistent vitamin K intake is essential for stable INR. Sudden increases in vitamin K (leafy greens, broccoli, liver) decrease warfarin effectiveness. Sudden decreases increase bleeding risk. Do not eliminate vitamin K foods; maintain consistent daily intake. Monitor INR regularly (target 2.0-3.0 for most indications)."),
  rpn("REX-PN","Cardiovascular",2,"A client experiencing chest pain is given sublingual nitroglycerin. The nurse should instruct the client to:",["Swallow the tablet with a full glass of water","Place the tablet under the tongue and let it dissolve","Chew the tablet thoroughly before swallowing","Take the tablet with food"],1,"Sublingual nitroglycerin: place under the tongue without swallowing (sublingual mucosa allows rapid absorption into the bloodstream). May repeat every 5 minutes for up to 3 doses. If pain persists after 3 doses, seek emergency care. Sit or lie down to prevent orthostatic hypotension. Burning/tingling indicates potency."),
  rpn("REX-PN","Cardiovascular",3,"A client with a pacemaker asks about using a microwave oven. The nurse should explain:",["Microwave ovens are dangerous and should never be used","Modern microwaves in good condition do not interfere with pacemakers","All electrical appliances should be avoided","Only gas stoves are safe to use"],1,"Modern pacemakers are well-shielded from electromagnetic interference. Household microwaves in good working condition are safe. Devices to avoid or use cautiously: MRI (unless MRI-conditional pacemaker), arc welding, large magnets, and some anti-theft systems (walk through normally, do not linger)."),
  rpn("REX-PN","Cardiovascular",2,"A client is diagnosed with hypertension. Which lifestyle modification should the nurse recommend first?",["Start a vigorous exercise program immediately","Reduce sodium intake, increase physical activity, and maintain a healthy weight","Eliminate all fats from the diet","Take herbal supplements for blood pressure"],1,"DASH lifestyle modifications for hypertension: sodium restriction (< 2,300 mg/day), regular aerobic exercise (150 min/week moderate intensity), weight management (even 5-10 lb loss helps), limit alcohol, increase fruits/vegetables/low-fat dairy, and smoking cessation. These can reduce SBP by 5-15 mmHg."),
  rpn("REX-PN","Respiratory",2,"A client with pneumonia should be encouraged to use the incentive spirometer correctly by:",["Inhaling quickly and forcefully through the device","Inhaling slowly and deeply, holding the breath for 3-5 seconds at maximum inspiration","Exhaling forcefully into the device to raise the indicator","Using the device once daily at bedtime"],1,"Correct IS technique: exhale normally, seal lips around mouthpiece, inhale slowly and deeply (not quickly) to raise the indicator, hold breath at peak for 3-5 seconds (allows alveolar expansion), exhale normally. Perform 10 times every 1-2 hours while awake. Set realistic volume goals."),
  rpn("REX-PN","Respiratory",3,"A nurse is caring for a client with a chest tube. Which finding requires immediate intervention?",["Gentle bubbling in the suction control chamber","Continuous bubbling in the water seal chamber","Drainage of 50 mL in the first hour after insertion","Fluctuation (tidaling) in the water seal chamber"],1,"Continuous bubbling in the water seal chamber indicates an air leak (in the system or from the client). Check connections, tubing, and dressing first. Intermittent bubbling during expiration/coughing is normal. Tidaling (fluid fluctuation with breathing) is normal and indicates a patent tube. Absence of tidaling may indicate obstruction."),
  rpn("REX-PN","Respiratory",2,"A client receiving oxygen via nasal cannula at 4 L/min is receiving approximately what FiO2?",["24%","36%","50%","100%"],1,"Nasal cannula FiO2 approximation: each liter adds approximately 4% to room air (21%). 1L=24%, 2L=28%, 3L=32%, 4L=36%, 5L=40%, 6L=44%. Maximum flow rate is 6 L/min. Higher flows require a different delivery device. Humidification recommended above 4 L/min to prevent mucous membrane drying."),
  rpn("REX-PN","Respiratory",2,"A client with COPD should receive oxygen therapy at:",["High-flow oxygen (10-15 L/min) to maximize oxygenation","Low-flow oxygen (1-2 L/min) to maintain the hypoxic respiratory drive","Any flow rate prescribed, as COPD clients can tolerate high flow","Room air only, as supplemental oxygen is contraindicated in COPD"],1,"Chronic CO2 retainers in COPD rely on hypoxic drive for breathing stimulus. High-flow oxygen can eliminate this drive, causing respiratory depression. Low-flow oxygen (1-2 L/min) maintains SpO2 88-92%. Monitor closely for decreased respiratory rate and level of consciousness when starting oxygen."),
  rpn("REX-PN","Renal",2,"A client with chronic kidney disease should limit which dietary intake?",["Carbohydrates","Potassium, phosphorus, and sodium","Vitamin C","Unsaturated fats"],1,"CKD dietary restrictions: potassium (hyperkalemia risk), phosphorus (hyperphosphatemia/bone disease), sodium (fluid retention/hypertension), and protein (in pre-dialysis stages to reduce uremic waste). High-potassium foods include bananas, oranges, potatoes, and tomatoes. High-phosphorus: dairy, nuts, cola."),
  rpn("REX-PN","Renal",3,"A client with a urinary tract infection has a urine culture showing greater than 100,000 colony-forming units. The nurse should anticipate:",["No treatment as this is a normal finding","Antibiotic therapy based on culture and sensitivity results","Increasing oral fluid intake only","Surgical intervention"],1,"Urine culture > 100,000 CFU/mL confirms UTI. Treatment is based on culture and sensitivity (C&S) results to ensure the organism is susceptible to the prescribed antibiotic. Common pathogens: E. coli (most common), Klebsiella, Proteus. Encourage fluid intake, complete full antibiotic course, and monitor symptoms."),
  rpn("REX-PN","Renal",2,"A client with a kidney stone is experiencing severe flank pain. The priority nursing intervention is:",["Restricting all fluids","Administering prescribed analgesics for pain management","Applying ice packs to the flank","Inserting a urinary catheter"],1,"Renal colic (kidney stone pain) is extremely severe. Priority is pain management with prescribed analgesics (NSAIDs like ketorolac, or opioids for severe pain). Additional interventions: strain all urine (catch the stone for analysis), increase fluids (if not contraindicated), monitor I&O, and assess for infection signs."),
  rpn("REX-PN","Endocrine",2,"A client with hypothyroidism should be taught to take levothyroxine:",["At bedtime with a snack","In the morning on an empty stomach, 30-60 minutes before breakfast","With iron supplements for better absorption","After eating a high-fat meal"],1,"Levothyroxine absorption is reduced by food, calcium, iron, antacids, and coffee. Take on an empty stomach with water, 30-60 minutes before eating. Consistent timing optimizes levels. Do not skip doses or double up. TSH is checked 6-8 weeks after dose changes. Lifelong therapy is usually required."),
  rpn("REX-PN","Endocrine",3,"A client in diabetic ketoacidosis has which characteristic finding?",["Slow, shallow breathing","Kussmaul respirations (deep, rapid breathing) and fruity breath odor","Hypertension and bradycardia","Peripheral edema and weight gain"],1,"DKA presentation: Kussmaul respirations (deep, rapid breathing compensating for metabolic acidosis by expelling CO2), fruity/acetone breath odor (ketone accumulation), dehydration, abdominal pain, nausea/vomiting, altered mental status. Lab findings: blood glucose > 250, pH < 7.3, HCO3 < 18, positive ketones."),
  rpn("REX-PN","Endocrine",2,"A client with type 2 diabetes should have HbA1c levels monitored. The target for most adults is:",["Less than 5%","Less than 7% (per ADA guidelines for most non-pregnant adults)","Less than 10%","Between 8-9%"],1,"ADA target HbA1c < 7% for most adults with diabetes (reduces microvascular complications). HbA1c reflects average blood glucose over 2-3 months. More stringent targets (< 6.5%) for select patients. Less stringent (< 8%) for older adults, limited life expectancy, or extensive comorbidities."),
  rpn("REX-PN","Gastrointestinal",2,"A client who had a colonoscopy should be monitored for which complication?",["Urinary retention","Bowel perforation and rectal bleeding","Respiratory depression only","Cardiac arrhythmias only"],1,"Post-colonoscopy complications: bowel perforation (severe abdominal pain, rigidity, fever), rectal bleeding (especially after polypectomy), and adverse reaction to sedation. Monitor vital signs, abdominal assessment, and stool characteristics. Mild bloating and gas are expected. Report severe abdominal pain, fever, or significant bleeding."),
  rpn("REX-PN","Gastrointestinal",2,"A client with a nasogastric tube on continuous suction is at risk for which acid-base imbalance?",["Respiratory acidosis","Metabolic alkalosis from loss of gastric acid (HCl)","Metabolic acidosis","Respiratory alkalosis"],1,"Continuous NG suction removes gastric acid (HCl), depleting hydrogen and chloride ions. This causes metabolic alkalosis (elevated pH, elevated HCO3). Also depletes potassium (hypokalemia) and sodium. Monitor electrolytes, replace losses, and assess for signs of alkalosis (confusion, muscle twitching, numbness)."),
  rpn("REX-PN","Gastrointestinal",3,"A client with liver cirrhosis has asterixis (liver flap). This finding is associated with:",["Vitamin deficiency","Hepatic encephalopathy from ammonia accumulation","Dehydration","Medication side effect"],1,"Asterixis (flapping tremor of dorsiflexed hands) is a classic sign of hepatic encephalopathy caused by elevated blood ammonia levels. The damaged liver cannot convert ammonia to urea. Treatment: lactulose (traps ammonia in the gut for fecal excretion) and rifaximin (reduces ammonia-producing gut bacteria). Restrict protein if severe."),
  rpn("REX-PN","Infection Control",2,"A client with suspected tuberculosis requires which type of isolation precautions?",["Contact precautions","Airborne precautions with an N95 respirator","Droplet precautions with a surgical mask","Standard precautions only"],1,"TB requires airborne precautions: negative-pressure room, N95 respirator (or PAPR) for all staff entering, door kept closed. TB bacilli are aerosolized as tiny droplet nuclei (< 5 microns) that remain suspended in air for hours. Patient wears surgical mask during transport. Isolation continues until 3 negative sputum AFB smears."),
  rpn("REX-PN","Infection Control",2,"The nurse is teaching a client about proper hand hygiene. Alcohol-based hand sanitizer is NOT effective against:",["Most bacteria","Clostridium difficile spores","Influenza virus","Common cold virus"],1,"C. difficile forms spores that are resistant to alcohol-based sanitizers. Soap and water with friction is required to physically remove spores from hands. Alcohol-based sanitizers are effective against most other bacteria and viruses. Hand hygiene is the single most important infection prevention measure."),
  rpn("REX-PN","Infection Control",2,"A nurse caring for a client with MRSA wound infection should use:",["Standard precautions only","Contact precautions with gown and gloves","Airborne precautions","Droplet precautions"],1,"MRSA requires contact precautions: gown and gloves upon entering the room, dedicated equipment, and enhanced hand hygiene with soap and water or alcohol-based sanitizer. Single room preferred. Remove PPE before leaving the room. MRSA is spread by direct contact with infected wounds or contaminated surfaces."),
  rpn("REX-PN","Fluid/Electrolytes",2,"A client with hyponatremia (sodium 128 mEq/L) may exhibit which symptom?",["Excessive thirst","Confusion and lethargy","Muscle rigidity","Hypertension"],1,"Hyponatremia (Na < 135 mEq/L) causes cellular swelling (water moves into cells). Neurological symptoms: confusion, lethargy, headache, nausea, seizures (severe cases). Normal sodium: 135-145 mEq/L. Treatment depends on cause: fluid restriction for dilutional, NS for depletional. Correct slowly to prevent osmotic demyelination."),
  rpn("REX-PN","Fluid/Electrolytes",3,"A client with a potassium level of 6.2 mEq/L should have the nurse prioritize:",["Encouraging potassium-rich foods","Obtaining an ECG and preparing for possible IV calcium gluconate administration","Increasing oral fluid intake","Administering potassium supplements"],1,"Hyperkalemia (K > 5.0 mEq/L) can cause fatal cardiac arrhythmias. Priority: cardiac monitoring (ECG for peaked T waves, widened QRS). IV calcium gluconate stabilizes the cardiac membrane. Insulin + glucose shifts K intracellularly. Kayexalate or dialysis removes K from the body."),
  rpn("REX-PN","Fluid/Electrolytes",2,"A client showing signs of fluid volume deficit (dehydration) would have:",["Distended neck veins and bounding pulse","Decreased skin turgor, dry mucous membranes, and concentrated urine","Crackles in the lungs and peripheral edema","Weight gain and hypertension"],1,"Dehydration signs: poor skin turgor (skin tenting), dry mucous membranes, concentrated dark urine, decreased urine output, increased heart rate, orthostatic hypotension, sunken eyes, and weight loss. Treatment: oral or IV fluid replacement depending on severity. Monitor I&O, daily weight, and vital signs."),
  rpn("REX-PN","Fluid/Electrolytes",3,"A client receiving IV normal saline at 125 mL/hr using a macrodrip set (15 drops/mL) should have the drip rate set at:",["15 drops per minute","31 drops per minute","42 drops per minute","63 drops per minute"],1,"IV drip rate formula: (Volume in mL x Drop factor) / Time in minutes = drops/minute. Calculation: (125 mL x 15 gtts/mL) / 60 min = 1875 / 60 = 31.25, rounded to 31 drops per minute. Common drop factors: macrodrip 10, 15, or 20 gtts/mL; microdrip always 60 gtts/mL."),
  rpn("REX-PN","Endocrine",2,"A client with diabetes experiencing hypoglycemia (blood glucose 55 mg/dL) should receive:",["Regular insulin injection","15 grams of fast-acting carbohydrate such as 4 oz juice or 3-4 glucose tablets","A full meal with protein and fat","Nothing by mouth until the provider is notified"],1,"Rule of 15 for hypoglycemia: give 15g fast-acting carbohydrate (4 oz juice, 3-4 glucose tablets, or 1 tablespoon honey/sugar), wait 15 minutes, recheck glucose. Repeat if still < 70 mg/dL. Follow with a complex carbohydrate and protein snack to prevent recurrence. Glucagon IM for unconscious clients."),
  rpn("REX-PN","Endocrine",2,"A client with diabetes should be taught to rotate insulin injection sites because:",["It makes injections less painful","Repeated injections in the same site cause lipodystrophy, which impairs insulin absorption","The body builds immunity to insulin at one site","It prevents needle contamination"],1,"Lipodystrophy (lipoatrophy or lipohypertrophy) from repeated injections at the same site impairs insulin absorption, leading to unpredictable glucose levels. Rotate within the same anatomic region (abdomen has most consistent absorption). Space injections at least 1 inch apart within the site."),
  rpn("REX-PN","Endocrine",3,"A nurse is mixing NPH and regular insulin in the same syringe. The correct procedure is to draw up:",["NPH insulin first, then regular insulin","Regular (clear) insulin first, then NPH (cloudy) insulin","Both insulins can be drawn in any order","Insulins should never be mixed"],1,"Clear before cloudy: draw regular (clear) insulin first to prevent contaminating the regular insulin vial with NPH (cloudy). Mnemonic: RN = Regular then NPH. Inject air into NPH vial first, then air into regular vial, draw regular, then draw NPH. Administer within 15 minutes of mixing."),
  rpn("REX-PN","Mental Health",2,"A client with major depressive disorder is prescribed sertraline. The nurse should teach that this medication may take how long to reach full therapeutic effect?",["24 hours","4-6 weeks for full therapeutic effect","1 week","3 months"],1,"SSRIs require 4-6 weeks for full therapeutic effect due to the time needed for serotonin receptor adaptation. Some improvement may be seen in 1-2 weeks. Continue medication even if feeling better. Do not stop abruptly (withdrawal syndrome). Monitor for suicidal ideation in the first weeks, especially in young adults."),
  rpn("REX-PN","Mental Health",2,"A nurse is caring for a client experiencing a manic episode. Which behavior is most characteristic?",["Withdrawn and isolated behavior","Grandiosity, decreased need for sleep, rapid speech, and impulsive behavior","Flat affect and social withdrawal","Obsessive hand washing"],1,"Mania characteristics: inflated self-esteem/grandiosity, decreased sleep need (feels rested after 3 hours), pressured/rapid speech, flight of ideas, distractibility, psychomotor agitation, and excessive involvement in risky activities. Priority: safety from impulsive behavior, reduce stimulation, set limits, and ensure nutrition/rest."),
  rpn("REX-PN","Mental Health",3,"A client on lithium therapy reports excessive thirst, frequent urination, and tremors. The nurse should:",["Encourage the client to drink less water","Check the lithium level as these may be signs of lithium toxicity","Increase the lithium dose","Reassure the client these are temporary side effects"],1,"Lithium toxicity signs: fine tremors progressing to coarse, excessive thirst and urination (nephrogenic DI), GI symptoms (nausea, diarrhea), confusion, slurred speech, and ataxia. Therapeutic range: 0.6-1.2 mEq/L. Check level immediately. Maintain adequate sodium and fluid intake. Report levels > 1.5 mEq/L."),
  rpn("REX-PN","Mental Health",2,"When a client in a psychiatric unit becomes agitated, the nurse should first:",["Apply physical restraints immediately","Use de-escalation techniques: calm voice, provide space, and offer choices","Administer PRN medication immediately","Call security and leave the room"],1,"De-escalation is the first-line approach for agitated clients: maintain calm demeanor, speak in a low/clear voice, maintain safe distance, avoid confrontational body language, acknowledge the client's feelings, offer choices (empowerment), and set clear boundaries. Physical restraints and forced medication are last resort."),
  rpn("REX-PN","Pediatrics",2,"A nurse is assessing a 2-year-old child. Which finding should be reported to the provider?",["The child speaks approximately 50 words","The child has not yet started walking","The child clings to the parent when the nurse approaches","The child's anterior fontanelle is still open"],3,"The anterior fontanelle normally closes by 12-18 months of age. An open fontanelle at age 2 may indicate hydrocephalus, hypothyroidism, rickets, or other conditions requiring evaluation. The posterior fontanelle closes by 2-3 months. Speaking 50 words and stranger anxiety are normal for age 2."),
  rpn("REX-PN","Pediatrics",2,"A child with acute otitis media is prescribed amoxicillin. The nurse should teach the parents to:",["Stop the medication when symptoms improve","Complete the entire course of antibiotics even if the child feels better","Crush the tablets and mix with hot food","Give the medication only at bedtime"],1,"Completing the full antibiotic course ensures eradication of the bacteria and prevents antibiotic resistance. Stopping early when symptoms improve may leave resistant bacteria. Amoxicillin suspension should be refrigerated, shaken well before each dose, and measured with a calibrated device."),
  rpn("REX-PN","Pediatrics",3,"A nurse is assessing a child for dehydration. Which finding indicates severe dehydration?",["Slightly decreased urine output","Sunken fontanelle, absent tears, and capillary refill greater than 3 seconds","Mild thirst and dry lips","Slightly elevated heart rate"],1,"Severe dehydration (> 10% body weight loss): sunken fontanelle (infants), sunken eyes, absent tears, very dry mucous membranes, capillary refill > 3 seconds, tachycardia, hypotension, decreased/absent urine output, lethargy/irritability. Requires immediate IV fluid resuscitation (20 mL/kg NS bolus)."),
  rpn("REX-PN","Maternal/Newborn",2,"A nurse is assessing a newborn at 1 minute after birth. The APGAR score component for heart rate greater than 100 bpm receives a score of:",["0","2","1","3"],1,"APGAR heart rate scoring: absent = 0, less than 100 bpm = 1, greater than 100 bpm = 2. A rate above 100 indicates good cardiac function. APGAR is assessed at 1 and 5 minutes. Total score 7-10 is reassuring, 4-6 requires some intervention, 0-3 requires immediate resuscitation."),
  rpn("REX-PN","Maternal/Newborn",2,"A postpartum client reports increased lochia rubra on day 5 postpartum. The nurse should:",["Document as a normal finding","Assess for uterine atony and notify the provider as lochia should be transitioning to serosa by day 4-5","Encourage breastfeeding more frequently","Apply an ice pack to the perineum"],1,"Lochia progression: rubra (red, days 1-3), serosa (pink/brown, days 4-10), alba (white/yellow, days 11-28). Increased rubra at day 5 suggests possible retained placental fragments, infection, or uterine atony. Assess fundal firmness, vital signs, and notify provider. Increased activity can temporarily increase flow."),
  rpn("REX-PN","Maternal/Newborn",3,"A nurse is caring for a client receiving oxytocin (Pitocin) for labor augmentation. The nurse should stop the infusion and notify the provider if:",["Contractions occur every 5 minutes lasting 45 seconds","Contractions occur every 1-2 minutes lasting more than 90 seconds with no relaxation between contractions","The client requests a position change","Mild bloody show is observed"],1,"Uterine hyperstimulation/tachysystole: contractions lasting > 90 seconds, occurring more frequently than every 2 minutes, or inadequate relaxation between contractions. This compromises uteroplacental blood flow and fetal oxygenation. Stop oxytocin, turn client to left side, increase IV fluids, administer oxygen, and notify provider."),
  rpn("REX-PN","Geriatrics",2,"An elderly client is at increased risk for drug toxicity due to:",["Enhanced liver metabolism","Decreased kidney function reducing drug excretion","Increased body water percentage","Increased serum albumin levels"],1,"Age-related renal decline reduces drug excretion, leading to accumulation and toxicity. Additional factors: decreased liver metabolism (reduced first-pass effect), decreased serum albumin (more free/active drug), increased body fat (fat-soluble drug accumulation), and decreased body water (higher water-soluble drug concentration)."),
  rpn("REX-PN","Geriatrics",2,"A nurse caring for an elderly client with dementia should communicate by:",["Giving complex, detailed instructions","Using simple, short sentences with one instruction at a time","Speaking loudly to ensure the client hears","Asking multiple questions simultaneously"],1,"Communication with dementia clients: use simple, short sentences; give one instruction at a time; allow adequate response time; use a calm, reassuring tone; maintain eye contact; use gestures and visual cues; avoid arguing or correcting; orient as needed; and approach from the front to avoid startling."),
  rpn("REX-PN","Geriatrics",3,"An elderly client taking multiple medications reports frequent falls. The nurse should first:",["Restrict the client to bed rest","Review the medication list for fall-risk medications (sedatives, antihypertensives, anticholinergics)","Order a brain CT scan","Apply restraints for safety"],1,"Medication review is essential: common fall-risk medications include benzodiazepines, sedatives/hypnotics, antihypertensives (orthostatic hypotension), anticholinergics (confusion, blurred vision), opioids, diuretics (dehydration), and muscle relaxants. Deprescribing unnecessary medications can significantly reduce fall risk."),
  rpn("REX-PN","Pain Management",2,"A nurse using the numeric pain rating scale should understand that this tool is most appropriate for:",["Infants and toddlers","Adults and children over age 7 who can quantify their pain","Clients who are unconscious","Clients with severe cognitive impairment"],1,"The numeric pain scale (0-10) requires the ability to understand numbers and assign a value to pain. Appropriate for adults and children >= 7 years. For young children: FACES scale (3-7 years). For infants: FLACC scale (face, legs, activity, cry, consolability). For non-verbal adults: behavioral scales."),
  rpn("REX-PN","Pain Management",2,"A client reports pain at a level of 7 out of 10 after surgery. The nurse should:",["Encourage the client to wait before administering pain medication","Administer prescribed analgesics and reassess pain within 30-60 minutes","Tell the client the pain is expected after surgery","Suggest deep breathing as the only intervention"],1,"Pain of 7/10 is moderate to severe and warrants prompt pharmacological intervention. Administer prescribed analgesics (IV onset 15-30 minutes, PO onset 30-60 minutes), reassess at appropriate time, and document. Non-pharmacological measures (positioning, ice, deep breathing) complement but do not replace analgesics."),
  rpn("REX-PN","Wound Care",2,"A nurse is assessing a wound and documents granulation tissue. This tissue appears:",["White or yellow and stringy (slough)","Red, beefy, and moist (indicating healthy healing)","Black and hard (eschar)","Pale and dry"],1,"Granulation tissue: red, beefy, moist, and slightly bumpy tissue filling the wound bed from the base upward. Indicates healthy wound healing (proliferative phase). Slough (yellow/white stringy tissue) requires debridement. Eschar (black/brown hard tissue) indicates necrotic tissue requiring removal for healing."),
  rpn("REX-PN","Wound Care",3,"A client has a wound VAC (vacuum-assisted closure) device. The nurse should ensure:",["The dressing is removed daily for wound assessment","Continuous negative pressure is maintained and the seal is intact","The tubing is clamped when the client ambulates","The device is turned off at night"],1,"Wound VAC maintains continuous or intermittent negative pressure to promote wound healing. Ensure: airtight seal (no air leaks), continuous suction (alarm sounds if seal breaks), tubing is not kinked, canister is not full, and assess wound per facility protocol (typically every 48-72 hours at dressing change). Do not clamp tubing."),
  rpn("REX-PN","Wound Care",2,"When irrigating a wound, the nurse should use:",["Hydrogen peroxide to kill bacteria","Prescribed wound irrigation solution (typically sterile normal saline) at the ordered pressure","Betadine solution for all wounds","Hot tap water"],1,"Sterile normal saline is the standard wound irrigation solution (non-cytotoxic, isotonic). Appropriate pressure: 4-15 psi (achievable with a 35 mL syringe and 19-gauge needle). Hydrogen peroxide and betadine are cytotoxic to healthy tissue and are generally avoided. Irrigate from clean to dirty area."),
  rpn("REX-PN","Pharmacology",2,"When administering ear drops to an adult, the nurse should pull the pinna:",["Down and back","Up and back to straighten the ear canal","Straight out laterally","No manipulation of the ear is needed"],1,"Adult ear drop administration: pull the pinna up and back to straighten the ear canal. For children under 3 years: pull the pinna down and back. Warm drops to body temperature (cold drops can cause vertigo). Have the client lie on the unaffected side for 5 minutes after instillation. Do not insert cotton deeply."),
  rpn("REX-PN","Pharmacology",2,"A nurse preparing to administer a subcutaneous injection should insert the needle at:",["90-degree angle for most adults with adequate subcutaneous tissue","15-degree angle","45-degree angle always","Parallel to the skin surface"],0,"Subcutaneous injection: 45-90 degree angle depending on patient size and needle length. For most adults with adequate SC tissue and a 5/8 inch needle: 90 degrees. Thin patients or short needle: 45 degrees. Pinch the skin, inject slowly, do not aspirate (per CDC guidelines). Common sites: abdomen, upper arm, thigh."),
  rpn("REX-PN","Safety",2,"A nurse discovers a fire in the client's room. The correct sequence of actions using RACE is:",["Remove, Alert, Contain, Extinguish","Rescue clients from danger, Activate the alarm, Contain the fire, Extinguish or Evacuate","Run, Alert, Call 911, Exit","Report, Assess, Contact, Evaluate"],1,"RACE fire safety: Rescue/Remove anyone in immediate danger, Activate the fire alarm (pull station) and call the fire department, Contain the fire (close doors and windows), Extinguish (if small and safe to do) or Evacuate. Use PASS for fire extinguisher: Pull pin, Aim at base, Squeeze handle, Sweep side to side."),
  rpn("REX-PN","Safety",2,"A nurse finds a client on the floor after a fall. The first action should be:",["Help the client back to bed immediately","Assess the client for injuries before moving them","Complete an incident report","Call the family to notify them"],1,"Post-fall: assess for injuries before moving (head/neck injury, fractures, pain). Check vital signs, neurological status, and range of motion. If spinal injury is suspected, do not move until evaluated. Once safe, assist to a comfortable position. Complete an incident report, notify the provider, and implement fall prevention measures."),
  rpn("REX-PN","Delegation",2,"The RPN/LPN should recognize that which task cannot be delegated to unlicensed assistive personnel?",["Measuring vital signs on a stable client","Administering medications","Assisting with bathing and hygiene","Measuring intake and output"],1,"Medication administration requires a licensed nurse (RN, RPN/LPN). It involves assessment, clinical judgment, knowledge of pharmacology, and potential for adverse effects. UAP tasks: vital signs on stable clients, I&O measurement, ambulation, bathing, feeding (non-complex), and specimen collection."),
  rpn("REX-PN","Delegation",3,"An RPN/LPN receives an order that seems inappropriate. The nurse should:",["Follow the order as written since the provider gave it","Clarify the order with the prescribing provider before carrying it out","Refuse to follow the order without explanation","Ask a colleague to carry out the order instead"],1,"Nurses are professionally and legally responsible for the care they provide. If an order seems inappropriate, unclear, or potentially harmful: verify with the prescribing provider, provide rationale for concern, document the communication, and follow the chain of command if the concern is not resolved. Never blindly follow an unsafe order."),
  rpn("REX-PN","Fundamentals",2,"A client's skin turgor is assessed by gently pinching the skin on the:",["Palm of the hand","Forearm or sternum","Bottom of the foot","Upper arm muscle"],1,"Skin turgor is best assessed on the forearm, sternum, or forehead (areas less affected by aging). Pinch the skin for a few seconds and release: normal skin returns to its original position quickly. Poor turgor (skin tenting > 2 seconds) suggests dehydration. In elderly clients, skin turgor on extremities may be unreliable due to loss of elasticity."),
  rpn("REX-PN","Fundamentals",2,"A nurse is teaching a client about deep breathing exercises to prevent postoperative pneumonia. The correct technique includes:",["Rapid shallow breathing 10 times per hour","Inhaling slowly through the nose, holding for 3 seconds, and exhaling slowly through pursed lips","Breathing rapidly through the mouth","Exhaling forcefully through the nose"],1,"Deep breathing exercises: sit upright or semi-Fowler's, inhale slowly through the nose (diaphragmatic breathing), hold for 3 seconds to allow alveolar expansion, exhale slowly through pursed lips (prolongs expiration, prevents airway collapse). Perform 10 times every 1-2 hours while awake. Splint incision with a pillow."),
  rpn("REX-PN","Pharmacology",2,"A client taking amlodipine should be warned about:",["Increased appetite","Peripheral edema and dizziness from blood pressure lowering","Hair loss","Increased blood glucose"],1,"Amlodipine (calcium channel blocker, dihydropyridine): common side effects include peripheral edema (dose-related ankle swelling from arteriolar vasodilation), dizziness, flushing, headache, and palpitations. Monitor blood pressure. Rise slowly to prevent orthostatic hypotension. Avoid grapefruit juice (increases drug levels)."),
  rpn("REX-PN","Pharmacology",3,"A client prescribed metformin should be instructed to report which serious symptom immediately?",["Mild nausea","Severe muscle pain, difficulty breathing, and unusual fatigue (symptoms of lactic acidosis)","Occasional headache","Mild diarrhea"],1,"Lactic acidosis is rare but potentially fatal with metformin. Symptoms: unexplained muscle pain/weakness, difficulty breathing, unusual fatigue, abdominal pain, dizziness, and cold/blue skin. Risk factors: renal impairment (eGFR < 30 contraindicated), liver disease, excessive alcohol, and contrast dye procedures."),
  rpn("REX-PN","Cardiovascular",2,"A client with peripheral arterial disease reports pain in the calves when walking that is relieved by rest. This symptom is called:",["Neuropathy","Intermittent claudication","Deep vein thrombosis","Peripheral neuropathy"],1,"Intermittent claudication: cramping pain in the legs (usually calves) during walking that is relieved by rest. Caused by inadequate blood supply to muscles during exertion due to atherosclerotic narrowing of arteries. Distinguish from rest pain (more severe PAD). Assessment includes ABI (ankle-brachial index)."),
  rpn("REX-PN","Cardiovascular",3,"A client with heart failure has crackles bilaterally in the lungs and is sitting upright to breathe. The nurse recognizes these as signs of:",["Right-sided heart failure","Left-sided heart failure with pulmonary congestion","Pneumonia","Normal findings in heart failure"],1,"Left-sided HF: blood backs up into the pulmonary circulation causing pulmonary edema. Signs: crackles (rales) on auscultation, dyspnea, orthopnea (needs to sit up to breathe), paroxysmal nocturnal dyspnea, cough with frothy/pink sputum. Right-sided HF: peripheral edema, JVD, hepatomegaly, ascites."),
  rpn("REX-PN","Respiratory",2,"A nurse is teaching a client how to use a metered-dose inhaler without a spacer. The correct instruction is:",["Inhale rapidly and hold breath for 1 second","Exhale fully, press the canister while inhaling slowly and deeply, then hold breath for 10 seconds","Spray the medication into the mouth while exhaling","Take rapid shallow breaths after pressing the canister"],1,"MDI technique without spacer: shake the inhaler, exhale fully, place mouthpiece between lips, begin slow deep inhalation while pressing the canister, continue inhaling slowly and deeply, hold breath for 10 seconds (medication deposits in airways), exhale slowly. Wait 1 minute between puffs. Rinse mouth after corticosteroid inhalers."),
  rpn("REX-PN","Safety",2,"A nurse is caring for a client with an allergy to latex. Which item should the nurse avoid using?",["Vinyl gloves","Standard latex examination gloves and balloons","Nitrile gloves","Paper tape"],1,"Latex allergy: avoid latex gloves, balloons, rubber bands, tourniquets with latex, adhesive bandages with latex, and some catheters. Alternatives: nitrile or vinyl gloves, non-latex tourniquets, silicone-based products. Allergic reactions range from contact dermatitis to severe anaphylaxis. Post latex-allergy signs in the room."),
  rpn("REX-PN","Wound Care",2,"A client with a Stage 3 pressure injury has a wound bed with yellow slough. The nurse should anticipate:",["No treatment needed","Wound debridement to remove non-viable tissue and promote healing","Applying dry gauze dressings","Immediate skin grafting"],1,"Slough (yellow/white necrotic tissue) delays healing and provides a medium for bacterial growth. Debridement methods: autolytic (moisture-retentive dressings), enzymatic (collagenase ointment), mechanical (wet-to-dry, irrigation), or sharp (by qualified provider). After debridement, use appropriate moist wound healing dressings."),
  rpn("REX-PN","Maternal/Newborn",2,"A newborn is placed skin-to-skin on the mother's chest immediately after birth. This practice promotes:",["Faster hospital discharge","Thermoregulation, bonding, and initiation of breastfeeding","Only warmth","Only bonding"],1,"Skin-to-skin (kangaroo care) benefits: thermoregulation (mother's body adjusts to infant's needs), colonization with maternal flora, promotes early breastfeeding initiation, stabilizes heart rate and breathing, reduces infant stress and crying, enhances bonding and maternal attachment, and improves breastfeeding success."),
  rpn("REX-PN","Pediatrics",2,"A nurse is calculating a medication dose for a child. The prescribed dose is 10 mg/kg/day. The child weighs 44 pounds. The total daily dose is:",["440 mg","200 mg","100 mg","350 mg"],1,"Step 1: Convert pounds to kilograms: 44 lbs / 2.2 = 20 kg. Step 2: Calculate dose: 10 mg/kg/day x 20 kg = 200 mg/day. Always verify pediatric doses against safe dosage ranges. Double-check calculations, especially for high-alert medications. Use weight in kilograms for dose calculations."),
  rpn("REX-PN","Geriatrics",2,"The nurse should be aware that elderly clients taking benzodiazepines are at increased risk for:",["Improved sleep quality without complications","Falls, confusion, and paradoxical agitation","Hypertension","Hyperglycemia"],1,"Benzodiazepines in elderly: increased sensitivity (prolonged half-life, reduced metabolism), higher fall risk (sedation, impaired coordination), confusion, paradoxical agitation (opposite of expected effect), respiratory depression, and dependence. Beers Criteria lists benzodiazepines as potentially inappropriate for elderly."),
  rpn("REX-PN","Infection Control",2,"A nurse is performing surgical hand antisepsis. The minimum scrub time is:",["30 seconds","2-5 minutes depending on the product used","10 seconds","15 minutes"],1,"Surgical hand scrub: 2-5 minutes (varies by product and facility protocol). Use antimicrobial soap or alcohol-based surgical hand rub. Scrub all surfaces including between fingers and under nails. Keep hands above elbows during scrub and rinse (water drains from clean to less clean areas). Do not touch anything after scrubbing."),
  rpn("REX-PN","Gastrointestinal",2,"A client is scheduled for a colonoscopy. Preoperative preparation typically includes:",["No special preparation is needed","Clear liquid diet the day before and bowel preparation solution as prescribed","A high-fiber diet for 3 days before","NPO for 1 week before the procedure"],1,"Colonoscopy prep: clear liquid diet the day before, prescribed bowel prep solution (polyethylene glycol or sodium phosphate) to cleanse the colon, NPO after midnight (or as directed). Adequate bowel prep is essential for visualization. Assess for electrolyte imbalances from prep. Review medication guidelines (hold anticoagulants per provider)."),
  rpn("REX-PN","Fluid/Electrolytes",2,"A client with hypocalcemia may exhibit which classic sign?",["Kussmaul respirations","Positive Chvostek sign (facial muscle twitching when facial nerve is tapped)","Flushed skin and diaphoresis","Decreased deep tendon reflexes"],1,"Hypocalcemia (Ca < 8.5 mg/dL): Chvostek sign (facial twitching when tapping CN VII), Trousseau sign (carpopedal spasm with BP cuff inflation), paresthesias, muscle cramps, tetany, seizures, prolonged QT on ECG. Causes: hypoparathyroidism, vitamin D deficiency, chronic renal failure. Treat with IV calcium gluconate."),
  rpn("REX-PN","Mental Health",2,"A nurse is caring for a client with anorexia nervosa. Which nursing intervention is a priority?",["Encouraging the client to eat large meals","Monitoring weight gain, electrolytes, and cardiac status during refeeding","Restricting all physical activity permanently","Confronting the client about their eating habits"],1,"Anorexia nervosa priority: monitor for refeeding syndrome (electrolyte shifts when nutrition is reintroduced after starvation). Watch potassium, phosphorus, magnesium, and cardiac rhythm. Start nutrition slowly and increase gradually. Monitor vital signs, daily weight, and I&O. Therapeutic relationship and consistent approach are essential."),
  rpn("REX-PN","Endocrine",2,"A client with diabetes should have their feet assessed at every visit because:",["It is routine for all hospitalized clients","Diabetic neuropathy reduces sensation, increasing the risk of undetected foot injuries leading to infection and amputation","Diabetes causes foot sweating","All diabetic clients have athlete's foot"],1,"Diabetic neuropathy reduces pain sensation (peripheral neuropathy) and peripheral vascular disease reduces blood flow. Minor injuries (blisters, cuts, pressure areas) may go unnoticed and develop into serious infections, ulcers, or gangrene requiring amputation. Teach daily foot inspection, proper footwear, and regular podiatric care."),
  rpn("REX-PN","Fundamentals",2,"A nurse is providing discharge teaching to a client. The most effective way to verify the client's understanding is:",["Asking if the client has any questions","Using the teach-back method, where the client explains the instructions in their own words","Handing the client a written pamphlet","Asking the client to sign the discharge form"],1,"Teach-back method: the nurse asks the client to explain what was taught in their own words. This verifies comprehension, identifies knowledge gaps, and allows for re-teaching. Asking 'Do you have any questions?' is less effective because clients may not realize what they do not understand."),
  rpn("REX-PN","Pain Management",3,"A nurse is caring for a client with chronic pain. Which non-pharmacological intervention can complement pain medication?",["Only medication can effectively treat chronic pain","Heat/cold application, guided imagery, massage, and relaxation techniques","Vigorous high-impact exercise","Sleep deprivation to reset pain pathways"],1,"Non-pharmacological pain management: heat/cold therapy, positioning, massage, relaxation techniques (deep breathing, progressive muscle relaxation), guided imagery, music therapy, distraction, TENS, acupuncture, and cognitive behavioral therapy. These complement (do not replace) pharmacological approaches and can reduce medication requirements."),
  rpn("REX-PN","Delegation",2,"When prioritizing client care, the nurse should attend to which client first?",["A client requesting a pain medication refill","A client whose oxygen saturation has dropped to 88% on room air","A client asking for help to the bathroom","A client requesting a meal tray"],1,"Prioritization uses the ABCs (Airway, Breathing, Circulation). SpO2 of 88% indicates hypoxemia requiring immediate assessment and intervention (apply supplemental oxygen, assess respiratory status). This is a breathing/oxygenation priority. Pain, elimination, and nutrition are important but not immediately life-threatening."),
  rpn("REX-PN","Safety",2,"A nurse accidentally administers the wrong medication to a client. The first action should be:",["Document the error in the medical record only","Assess the client for adverse effects and notify the provider immediately","Conceal the error to avoid consequences","Wait to see if the client has any reaction before reporting"],1,"Wrong medication: immediately assess the client for adverse effects, check vital signs, notify the provider (who determines treatment and monitoring), complete an incident/occurrence report, document the event objectively in the medical record, and monitor the client closely. Transparency protects the client and enables system improvement."),
  rpn("REX-PN","Nutrition",2,"A client receiving total parenteral nutrition (TPN) should have which lab value monitored most closely?",["Hemoglobin and hematocrit","Blood glucose levels (hyperglycemia is a common complication)","Platelet count","Serum sodium only"],1,"TPN contains high concentrations of dextrose, which can cause hyperglycemia. Monitor blood glucose every 4-6 hours initially (per protocol). Other monitoring: electrolytes (K, Mg, Phos), liver function, triglycerides, and fluid balance. TPN is administered through a central line due to its high osmolarity. Use an infusion pump."),
  rpn("REX-PN","Ethics/Legal",2,"A client's family member asks the nurse for information about the client's diagnosis. The nurse should:",["Share all information with the family freely","Verify the client has given consent for information sharing before disclosing any protected health information","Tell the family to call the doctor","Refuse all communication with the family"],1,"HIPAA/privacy laws: patient health information can only be shared with the client's consent (or designated health care proxy). Verify who is authorized to receive information. Even well-meaning family members cannot access PHI without consent. Document the client's preferences regarding information sharing."),
  rpn("REX-PN","Neurological",2,"A client who has had a stroke and has difficulty swallowing should be placed in which position for eating?",["Supine position","Upright sitting position (90 degrees) with head slightly flexed forward","Left lateral position","Trendelenburg position"],1,"Dysphagia positioning: sit upright at 90 degrees (reduces aspiration risk by using gravity to direct food toward the esophagus), chin slightly tucked (closes the airway during swallowing), and remain upright for 30 minutes after eating. Thickened liquids and soft foods may be prescribed based on swallowing assessment."),
  rpn("REX-PN","Neurological",3,"A client with increased intracranial pressure should be positioned with the head of bed at:",["Flat (0 degrees)","30 degrees elevation with head in neutral midline position","90 degrees","Trendelenburg position"],1,"HOB 30 degrees promotes venous drainage from the brain through the jugular veins, reducing ICP. Keep head midline (turning or flexing the head compresses jugular veins, impeding drainage). Avoid hip flexion, Valsalva maneuver, and clustering care activities. Monitor neurological status and vital signs frequently."),
  rpn("RPN-CAT","Musculoskeletal",2,"A client with a new cast should be taught to report which finding immediately?",["Mild itching under the cast","Numbness, tingling, or inability to move fingers/toes distal to the cast","Mild swelling in the first 24 hours","Slight warmth of the cast while drying"],1,"Neurovascular compromise (compartment syndrome) signs: 5 Ps - Pain (out of proportion, unrelieved by elevation or analgesics), Pallor, Pulselessness, Paresthesia (numbness/tingling), and Paralysis. Report any neurovascular changes immediately. Elevate the extremity, assess circulation frequently (color, sensation, movement, pulses, cap refill)."),
  rpn("RPN-CAT","Musculoskeletal",3,"A client with osteoporosis should be taught that the most important preventive measure includes:",["High-sodium diet","Weight-bearing exercise combined with adequate calcium and vitamin D intake","Bed rest to prevent fractures","Limiting sun exposure"],1,"Osteoporosis prevention: weight-bearing exercise (walking, jogging, dancing stimulates bone formation), calcium intake (1,000-1,200 mg/day), vitamin D (600-800 IU/day), fall prevention, and avoiding smoking and excessive alcohol. DEXA scan for diagnosis and monitoring. Bisphosphonates or other medications for treatment."),
  rpn("REX-PN","Hematological",2,"A client with anemia may present with which symptoms?",["Hypertension and weight gain","Fatigue, pallor, tachycardia, and shortness of breath on exertion","Fever and productive cough","Joint pain and swelling"],1,"Anemia reduces oxygen-carrying capacity, causing tissue hypoxia. Compensatory mechanisms: tachycardia (increased cardiac output), tachypnea, and vasodilation. Symptoms: fatigue, weakness, pallor (skin, conjunctivae, nail beds), dyspnea on exertion, dizziness, and headache. Severity correlates with hemoglobin level and rate of decline."),
  rpn("REX-PN","Hematological",3,"A client receiving heparin therapy should have which lab value monitored?",["INR/PT","aPTT (activated partial thromboplastin time)","Platelet count only","Serum calcium"],1,"Heparin monitoring: aPTT (target 1.5-2.5 times control, typically 60-80 seconds). Monitor every 6 hours until therapeutic, then daily. Also monitor platelet count (HIT - heparin-induced thrombocytopenia). Protamine sulfate is the reversal agent. Warfarin monitoring uses PT/INR. LMWH may use anti-Xa levels."),
  rpn("REX-PN","Immunological",2,"A client who has had a splenectomy is at increased risk for:",["Only minor viral infections","Overwhelming post-splenectomy infection from encapsulated organisms","No increased infection risk","Only fungal infections"],1,"The spleen filters encapsulated bacteria (Streptococcus pneumoniae, Haemophilus influenzae, Neisseria meningitidis). Post-splenectomy: lifelong increased infection risk. Vaccinate against these organisms before splenectomy if possible. Patients should seek immediate medical attention for any fever or signs of infection."),
  rpn("REX-PN","Integumentary",2,"A client with a burn injury to the anterior trunk and both entire arms has what percentage of total body surface area burned using the Rule of Nines?",["27%","36%","45%","18%"],1,"Rule of Nines for adults: head/neck = 9%, each arm = 9% (both = 18%), anterior trunk = 18%, posterior trunk = 18%, each leg = 18%, perineum = 1%. This client: anterior trunk (18%) + both arms (18%) = 36% TBSA. Burns > 20% TBSA require fluid resuscitation (Parkland formula)."),
  rpn("REX-PN","Emergency",2,"A nurse suspects a client is having a stroke. Which assessment tool should be used for rapid screening?",["Glasgow Coma Scale only","Cincinnati Prehospital Stroke Scale or FAST (Face drooping, Arm drift, Speech difficulty, Time to call emergency)","Pain assessment scale","Fall risk assessment"],1,"FAST stroke screening: Face (ask to smile - uneven?), Arms (raise both - one drift down?), Speech (repeat a sentence - slurred?), Time (note onset time, call emergency). Time is critical: 'Time is brain.' tPA can be given within 4.5 hours of symptom onset. Every minute delay means more brain tissue lost."),
  rpn("REX-PN","Emergency",3,"A client experiencing anaphylaxis should receive which medication first?",["Diphenhydramine (Benadryl)","Epinephrine (intramuscular injection) as the first-line treatment","IV corticosteroids","Oral antihistamines"],1,"Anaphylaxis first-line: epinephrine IM (vastus lateralis, 0.3-0.5 mg of 1:1,000 for adults). Epinephrine reverses bronchospasm, vasodilation, and mucosal edema. May repeat every 5-15 minutes. Then: supplemental oxygen, IV fluids for hypotension, antihistamines (H1 and H2 blockers), and corticosteroids (prevent biphasic reaction)."),
  rpn("REX-PN","Oncology",2,"A client receiving chemotherapy develops neutropenia (ANC < 1000). The nurse should implement:",["No special precautions","Neutropenic precautions: private room, mask for visitors with illness, hand hygiene, avoid fresh flowers and raw foods","Only hand hygiene","Droplet precautions"],1,"Neutropenic precautions: private room, meticulous hand hygiene, no fresh flowers/plants (mold spores), no raw fruits/vegetables (bacteria), mask for symptomatic visitors, avoid rectal temperatures and suppositories, monitor temperature frequently. ANC < 500 = severe neutropenia with high infection risk. Report fever > 100.4F immediately."),
  rpn("REX-PN","Oncology",3,"A nurse caring for a client with cancer who develops tumor lysis syndrome should anticipate:",["Hypocalcemia and hyperuricemia","Hyperkalemia, hyperphosphatemia, hypocalcemia, and hyperuricemia","Only elevated white blood cell count","Fluid volume deficit"],0,"TLS: rapid cell destruction releases intracellular contents. Lab findings: hyperkalemia (cardiac arrhythmia risk), hyperphosphatemia (binds calcium), hypocalcemia (secondary to hyperphosphatemia), and hyperuricemia (uric acid nephropathy risk). Treatment: IV fluids, allopurinol or rasburicase, electrolyte management, and possible dialysis."),
  rpn("REX-PN","Nutrition",2,"A client with dysphagia should have their diet modified to include:",["Regular foods and thin liquids","Thickened liquids and pureed or mechanically altered foods as recommended by speech therapy","Only IV fluids","Hot liquids to relax the throat muscles"],1,"Dysphagia diet modifications based on speech-language pathologist assessment: thickened liquids (nectar-thick, honey-thick, or pudding-thick), pureed, mechanically altered, or soft foods. International Dysphagia Diet Standardization Initiative (IDDSI) provides standardized terminology. Thin liquids are the most aspirated consistency."),
  rpn("REX-PN","Nutrition",2,"A client on a clear liquid diet can consume which of the following?",["Milk and cream soups","Broth, gelatin, popsicles, clear juices (apple, grape), and tea","Mashed potatoes and pudding","Yogurt and smoothies"],1,"Clear liquid diet: transparent fluids at room temperature or body temperature. Includes: broth (beef, chicken), plain gelatin, clear juices without pulp (apple, grape, cranberry), popsicles, hard candy, tea, coffee, and water. Purpose: hydration, minimal residue, easily digestible. Progress to full liquid, then soft diet as tolerated."),
  rpn("REX-PN","Fundamentals",2,"Before administering any medication, the nurse should verify the five rights. These are:",["Right patient, right drug, right dose, right route, and right time","Right patient, right room, right dose, right color, and right shift","Right doctor, right hospital, right chart, right form, and right patient","Right nurse, right shift, right chart, right drug, and right patient"],0,"Five Rights of Medication Administration: Right Patient (check ID band using 2 identifiers), Right Drug (verify against MAR), Right Dose (calculate if needed), Right Route (oral, IV, IM, etc.), Right Time (within 30-minute window). Additional rights include right documentation, right reason, right to refuse, and right education."),
  rpn("RPN-CAT","Cardiovascular",3,"A client with a central venous access device (CVAD) develops sudden dyspnea, chest pain, and tachycardia during a dressing change. The nurse should suspect:",["Pneumonia","Air embolism and should immediately clamp the line, position the client in left lateral Trendelenburg position","Anxiety attack","Medication reaction"],1,"Air embolism during CVAD care: air enters the venous system through the catheter hub. Immediate actions: clamp the catheter, position client left lateral Trendelenburg (air rises to right atrium apex, preventing pulmonary artery obstruction), administer oxygen, notify provider. Prevention: keep hub capped, have client perform Valsalva during tubing changes."),
  rpn("REX-PN","Renal",2,"A client with a Foley catheter should have the drainage bag positioned:",["At the level of the bladder","Below the level of the bladder to facilitate gravity drainage","Above the level of the bladder","On the bed beside the client"],1,"Foley drainage bag positioning: always below the level of the bladder (gravity drainage). Never place on the floor (contamination). Secure tubing to prevent kinking or pulling. Empty the bag when 2/3 full or every 8 hours. Do not disconnect the closed drainage system (infection risk). Monitor and record output."),
  rpn("REX-PN","Endocrine",2,"A client with Cushing syndrome presents with which characteristic features?",["Weight loss and hypotension","Moon face, buffalo hump, central obesity, and purple striae","Increased muscle mass and energy","Hyperpigmentation of the skin"],1,"Cushing syndrome (cortisol excess): moon face (round, full face), buffalo hump (fat pad at base of neck), central obesity (truncal), thin extremities, purple/violaceous striae, thin skin that bruises easily, hyperglycemia, hypertension, osteoporosis, and immunosuppression. Causes: corticosteroid therapy (most common), pituitary adenoma, adrenal tumor."),
  rpn("REX-PN","Gastrointestinal",2,"A client with GERD should be taught which lifestyle modification?",["Lie down immediately after eating for comfort","Elevate the head of bed 6-8 inches and avoid eating 2-3 hours before bedtime","Eat large meals to prevent frequent snacking","Drink coffee to improve digestion"],1,"GERD lifestyle modifications: elevate HOB 6-8 inches (blocks reduce gravity, pillows alone are insufficient), avoid eating 2-3 hours before bed, eat small frequent meals, avoid trigger foods (caffeine, alcohol, chocolate, peppermint, fatty/spicy foods), maintain healthy weight, and avoid tight clothing around the abdomen."),
  rpn("REX-PN","Infection Control",2,"The most important intervention to prevent catheter-associated urinary tract infections (CAUTI) is:",["Changing the catheter daily","Removing the catheter as soon as it is no longer medically necessary","Irrigating the catheter with antibiotics daily","Applying antibiotic ointment to the meatus"],1,"CAUTI prevention bundle: remove the catheter as early as possible (daily reassessment of need), maintain a closed drainage system, keep the bag below bladder level, perform hand hygiene before and after catheter care, perform perineal hygiene, and secure the catheter to prevent pulling. Catheter duration is the strongest risk factor for CAUTI."),
  rpn("REX-PN","Fundamentals",2,"A nurse should assess the client's level of consciousness using the Glasgow Coma Scale which evaluates:",["Only verbal response","Eye opening, verbal response, and motor response","Only motor response","Eye opening and pain response"],1,"Glasgow Coma Scale (GCS): Eye opening (4: spontaneous, 3: to voice, 2: to pain, 1: none), Verbal response (5: oriented, 4: confused, 3: inappropriate words, 2: incomprehensible sounds, 1: none), Motor response (6: obeys commands, 5: localizes pain, 4: withdraws, 3: abnormal flexion, 2: extension, 1: none). Total range: 3-15. Score <= 8 = severe."),
  rpn("RPN-CAT","Pharmacology",3,"A client prescribed warfarin has an INR of 5.0 with no active bleeding. The nurse should anticipate:",["Increasing the warfarin dose","Holding warfarin and administering vitamin K if ordered by the provider","Administering fresh frozen plasma immediately","Continuing the warfarin at the current dose"],1,"INR > 4.0 without bleeding: hold warfarin, may give low-dose oral vitamin K (1-2.5 mg). INR > 10 without bleeding: hold warfarin, give vitamin K 2.5-5 mg orally. Active bleeding with any elevated INR: vitamin K IV, fresh frozen plasma or PCC. Monitor INR daily until therapeutic range (2.0-3.0) is restored."),
  rpn("REX-PN","Maternal/Newborn",2,"A nurse is assessing a newborn for jaundice. Which area should be assessed first?",["The feet and toes","The face and sclera (jaundice progresses cephalocaudal, appearing first in the head)","The abdomen only","The extremities"],1,"Neonatal jaundice progresses cephalocaudal (head to toe): face/sclera first, then trunk, then extremities. Blanch the skin to assess for yellow coloring. Physiological jaundice appears after 24 hours (day 2-3 in term infants). Jaundice within the first 24 hours is pathological and requires immediate evaluation (hemolytic disease)."),
  rpn("REX-PN","Pediatrics",2,"A nurse administering an immunization to an infant should use which injection site?",["Deltoid muscle","Vastus lateralis (anterolateral thigh)","Ventrogluteal","Dorsogluteal"],1,"Vastus lateralis is the preferred IM injection site for infants and young children (< 12 months): well-developed muscle, no major nerves or blood vessels, easily accessible. Deltoid can be used for children >= 1 year (toddlers) if muscle mass is adequate. Ventrogluteal can be used for children who have been walking."),
  rpn("REX-PN","Geriatrics",2,"An elderly client has been prescribed a new sleeping medication. The nurse should be concerned about which increased risk?",["Improved sleep quality","Falls related to sedation and impaired balance","Weight gain","Improved daytime alertness"],1,"Sedative/hypnotic medications in elderly: increased sensitivity (altered pharmacokinetics), prolonged effects, impaired balance and coordination, confusion upon waking (especially nocturnal bathroom visits), and increased fall risk. Non-pharmacological sleep interventions should be tried first: sleep hygiene, consistent routine, and limiting daytime napping."),
  rpn("REX-PN","Fundamentals",2,"When transferring a client from bed to wheelchair, the nurse should place the wheelchair:",["On the affected/weak side","On the client's stronger side to facilitate the transfer","At the foot of the bed","Across the room"],1,"Position the wheelchair on the client's stronger/unaffected side: the client can lead with the stronger leg, bear weight on the stronger side, and use the stronger arm for support. Lock wheelchair brakes, place the chair at a 45-degree angle to the bed, and have the client stand momentarily before pivoting to sit."),
  rpn("REX-PN","Pharmacology",2,"A client taking prednisone long-term should be taught to never stop the medication abruptly because:",["It causes weight gain","Abrupt discontinuation can cause adrenal crisis due to suppressed adrenal function","It is addictive","The symptoms will immediately return"],1,"Long-term corticosteroid use suppresses the hypothalamic-pituitary-adrenal (HPA) axis. Abrupt withdrawal can cause adrenal crisis (hypotension, shock, death) because the adrenal glands cannot produce adequate cortisol quickly enough. Taper gradually to allow adrenal recovery. Stress dosing may be needed during illness or surgery."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const q of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11})`);
      params.push(q.tier,q.exam,"multiple_choice","published",q.stem,JSON.stringify(q.options),JSON.stringify([q.correct]),q.rationale,q.diff,q.bs,"BOTH",hash(q.stem));
      idx += 12;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
  }
  console.log(`[RPN-B5] Inserted ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}
main().catch(e => { console.error(e); process.exit(1); });
